--
-- Table structure for table `client_main_information`
--

DROP TABLE IF EXISTS `client_main_information`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `client_main_information` (
  `id` bigint(20) unsigned NOT NULL AUTO_INCREMENT,
  `client_id` bigint(20) NOT NULL,
  `user_id` bigint(20) DEFAULT NULL COMMENT 'Usuario del sistema',
  `user` varchar(255) DEFAULT NULL COMMENT 'Mikrotik User',
  `password` varchar(255) DEFAULT NULL COMMENT 'Mikrotik User Password',
  `estado` varchar(255) NOT NULL DEFAULT 'Nuevo' COMMENT 'Nuevo => Nuevo(Todavía no conectado),\n                Activo => Activado, Inactivo => Inactivo(No puede utilizar los servicios),\n                Bloqueado => Bloqueado\n            ',
  `type_of_billing_id` bigint(20) DEFAULT NULL,
  `ift` varchar(255) DEFAULT NULL,
  `name` varchar(255) NOT NULL,
  `father_last_name` varchar(255) DEFAULT NULL,
  `mother_last_name` varchar(255) DEFAULT NULL,
  `email` varchar(255) DEFAULT NULL,
  `phone` varchar(255) DEFAULT NULL,
  `phone2` varchar(255) DEFAULT NULL,
  `phone3` varchar(255) DEFAULT NULL,
  `nif_pasaport` varchar(255) DEFAULT NULL COMMENT 'RFC/CURP',
  `partner_id` bigint(20) DEFAULT NULL,
  `street` varchar(255) DEFAULT NULL,
  `external_number` varchar(255) DEFAULT NULL,
  `internal_number` varchar(255) DEFAULT NULL,
  `zip` varchar(255) DEFAULT NULL,
  `colony_id` varchar(255) DEFAULT NULL,
  `municipality_id` varchar(255) DEFAULT NULL,
  `state_id` bigint(20) unsigned DEFAULT NULL,
  `address` varchar(255) DEFAULT NULL,
  `location_id` bigint(20) DEFAULT NULL,
  `geodata` varchar(255) DEFAULT NULL,
  `geo_data` varchar(255) DEFAULT NULL,
  `discharge_date` varchar(255) DEFAULT NULL COMMENT 'fecha de alta',
  `activation_date` varchar(255) DEFAULT NULL COMMENT 'fecha en la que se convirtio de crm a cliente',
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  `seller_id` bigint(20) DEFAULT NULL,
  `medium_id` bigint(20) DEFAULT NULL,
  `deleted_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=4472 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

